#include <stdio.h>
#define MOD 7051954
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, L, A, B;
        scanf("%d %d %d %d", &N, &L, &A, &B);
        char mcq[N + 1];
        scanf("%s", mcq);
        int next_plus[N], next_minus[N], plus_cnt[N], minus_cnt[N];
        int np = -1, nm = -1, cp = 0, cm = 0;
        for (int i = N - 1; i >= 0; --i) {
            if (mcq[i] == '+') {
                np = i;
                cp++;
            } else {
                nm = i;
                cm++;
            }
            next_plus[i] = np;
            next_minus[i] = nm;
            plus_cnt[i] = cp;
            minus_cnt[i] = cm;
        }
        int farthest_right = (A + plus_cnt[0]) < L ? (A + plus_cnt[0]) : L;
        int farthest_left = (A - minus_cnt[0]) > 0 ? (A - minus_cnt[0]) : 0;
        if (B < farthest_left || B > farthest_right) {
            printf("0\n");
            continue;
        }
        int dp[farthest_right - farthest_left + 1][N + 1];
        for (int i = 0; i <= farthest_right - farthest_left; i++) {
            for (int j = 0; j <= N; j++) {
                dp[i][j] = 0;
            }
        }
        dp[B - farthest_left][N] = 1;
        for (int command_start = N - 1; command_start >= 0; --command_start) {
            for (int curposition = farthest_left; curposition <= farthest_right; ++curposition) {
                int cur_ind = curposition - farthest_left;
                int np = next_plus[command_start];
                int nm = next_minus[command_start];
                if (np != -1 && curposition + 1 <= farthest_right) {
                    dp[cur_ind][command_start] += dp[cur_ind + 1][np + 1];
                    dp[cur_ind][command_start] %= MOD;
                }
                if (nm != -1 && curposition - 1 >= farthest_left) {
                    dp[cur_ind][command_start] += dp[cur_ind - 1][nm + 1];
                    dp[cur_ind][command_start] %= MOD;
                }
                if (curposition == B) {
                    dp[cur_ind][command_start]++;
                    dp[cur_ind][command_start] %= MOD;
                }
            }
        }
        printf("%d\n", dp[A - farthest_left][0]);
    }
    return 0;
}

